const { isAIAvailable, streamChat, QUICK_QUESTIONS, fetchAIChatEnabled, isAIChatEnabledSync } = require('../../utils/aiService.js')
const { getUpcomingMissions, getCompletedMissions } = require('../../utils/api.js')
const { getMembershipState, isPro, getAiChatRemaining, recordAiChatUse, FREE_LIMITS, isMembershipEnabled } = require('../../utils/membership.js')

let _msgId = 0
function nextMsgId() { return 'msg_' + (++_msgId) + '_' + Date.now() }

const MAX_HISTORY_ROUNDS = 8
const MAX_DAILY_QUESTIONS = 10
const DAILY_QUOTA_KEY = '_ai_chat_daily_quota'

function getDailyQuotaInfo() {
  try {
    const data = wx.getStorageSync(DAILY_QUOTA_KEY)
    const today = new Date().toDateString()
    if (data && data.date === today) {
      return { count: data.count || 0, date: today }
    }
    return { count: 0, date: today }
  } catch (e) {
    return { count: 0, date: new Date().toDateString() }
  }
}

function incrementDailyQuota() {
  const info = getDailyQuotaInfo()
  info.count += 1
  try { wx.setStorageSync(DAILY_QUOTA_KEY, info) } catch (e) {}
  return info.count
}

function getRemainingQuota() {
  const info = getDailyQuotaInfo()
  return Math.max(0, MAX_DAILY_QUESTIONS - info.count)
}

const FAB_SIZE_RPX = 96
const EDGE_MARGIN = 12

Component({
  properties: {},

  data: {
    visible: false,
    panelMounted: false,
    panelHeight: 0,
    keyboardHeight: 0,
    // 初始坐标放到屏幕外，作为终极兜底；正式坐标在 attached 同步算完后一次性 setData
    fabX: -9999,
    fabY: -9999,
    _fabSize: 0,
    // 与 nasa-float 同款：把窗口宽度作为"渲染就绪"信号——
    // wxml 里用 `_winW > 0` 做 wx:if 判断，初始 0 必为 false，
    // initialRenderingCache: "static" 模式下也能正确求值。
    _winW: 0,
    _winH: 0,
    messages: [],
    inputValue: '',
    sending: false,
    scrollTarget: '',
    quickQuestions: QUICK_QUESTIONS,
    inputFocus: false,
    hasHistory: false,
    errorMsgId: '',
    aiChatHidden: false,
    particles: []
  },

  lifetimes: {
    attached() {
      // ── 第一步：同步算位置并一次 setData 全部就位 ──
      // 仿 nasa-float 写法：把窗口宽度等所有渲染前置数据放到同一次 setData，
      // 避免拆分 setData 给渲染层留出"用初始 (0,0) 渲染一帧"的空隙。
      // 体验版 / lazyCodeLoading 下组件 chunk 加载更晚，多 setData 会暴露这一帧。
      const sys = wx.getWindowInfo()
      const ratio = sys.windowWidth / 750
      const fabSize = Math.round(FAB_SIZE_RPX * ratio)
      const nasaY = Math.round(sys.windowHeight * 0.65)
      const nasaBtnSize = Math.round(96 * ratio)

      // 同步读 storage 判断 AI 是否启用，确保第一次 setData 就是终态
      const aiEnabledSync = isAIChatEnabledSync()

      this.setData({
        panelHeight: Math.round(sys.windowHeight * 0.72),
        fabX: sys.windowWidth - fabSize - EDGE_MARGIN,
        fabY: nasaY + nasaBtnSize + Math.round(16 * ratio),
        _fabSize: fabSize,
        _winW: sys.windowWidth,
        _winH: sys.windowHeight,
        aiChatHidden: !aiEnabledSync
      })

      // ── 第二步：异步刷新远程开关（结果回来再修正可见性，与位置无关，不会再闪） ──
      fetchAIChatEnabled().then((enabled) => {
        this.setData({ aiChatHidden: !enabled })
      })

      // ── 第三步：与 fab 渲染无关的副作用，放最后 ──
      this._preloadLaunchData()

      this._kbHandler = (res) => {
        const h = res.height || 0
        if (this.data.visible) {
          this.setData({ keyboardHeight: h })
          if (h > 0) {
            setTimeout(() => this.setData({ scrollTarget: 'msg-bottom' }), 100)
          }
        }
      }
      wx.onKeyboardHeightChange(this._kbHandler)
    },

    detached() {
      if (this._kbHandler) {
        try { wx.offKeyboardHeightChange(this._kbHandler) } catch (e) {}
      }
    }
  },

  methods: {
    /* ── 拖拽 FAB ── */
    onFabTouchStart(e) {
      const t = e.touches[0]
      this._fabStartX = t.clientX
      this._fabStartY = t.clientY
      this._fabOriginX = this.data.fabX
      this._fabOriginY = this.data.fabY
      this._fabDragging = false
    },

    onFabTouchMove(e) {
      const t = e.touches[0]
      const dx = t.clientX - this._fabStartX
      const dy = t.clientY - this._fabStartY
      if (Math.abs(dx) > 5 || Math.abs(dy) > 5) this._fabDragging = true

      const { _fabSize, _winW, _winH } = this.data
      const newX = Math.max(0, Math.min(_winW - _fabSize, this._fabOriginX + dx))
      const newY = Math.max(0, Math.min(_winH - _fabSize, this._fabOriginY + dy))
      this.setData({ fabX: newX, fabY: newY })

      if (this._fabDragging) {
        this._spawnParticle(newX + _fabSize / 2, newY + _fabSize / 2)
      }
    },

    onFabTouchEnd() {
      if (this._fabDragging) {
        this._snapFabToEdge()
        this._fadeOutParticles()
        return
      }
      this.openChat()
    },

    _spawnParticle(cx, cy) {
      if (!this._particleList) this._particleList = []
      if (!this._particleId) this._particleId = 0
      const now = Date.now()
      if (this._lastParticleTs && now - this._lastParticleTs < 8) return
      this._lastParticleTs = now

      const offsetX = (Math.random() - 0.5) * 16
      const offsetY = (Math.random() - 0.5) * 16
      const size = 0.5 + Math.random() * 1.0
      const p = { id: ++this._particleId, x: cx + offsetX, y: cy + offsetY, opacity: 1, scale: size }
      this._particleList.push(p)
      if (this._particleList.length > 80) this._particleList = this._particleList.slice(-80)
      this.setData({ particles: this._particleList })

      setTimeout(() => {
        this._particleList = this._particleList.map(item =>
          item.id === p.id ? { ...item, opacity: 0, scale: 0.1 } : item
        )
        this.setData({ particles: this._particleList })
      }, 50)

      setTimeout(() => {
        this._particleList = this._particleList.filter(item => item.id !== p.id)
        this.setData({ particles: this._particleList })
      }, 1800)
    },

    _fadeOutParticles() {
      if (!this._particleList || !this._particleList.length) return
      this._particleList = this._particleList.map(p => ({ ...p, opacity: 0, scale: 0.05 }))
      this.setData({ particles: this._particleList })
      setTimeout(() => {
        this._particleList = []
        this.setData({ particles: [] })
      }, 1600)
    },

    _snapFabToEdge() {
      const { fabX, fabY, _fabSize, _winW, _winH } = this.data
      const newX = (fabX + _fabSize / 2) < (_winW / 2) ? EDGE_MARGIN : _winW - _fabSize - EDGE_MARGIN
      const newY = Math.max(EDGE_MARGIN, Math.min(_winH - _fabSize - EDGE_MARGIN, fabY))
      this.setData({ fabX: newX, fabY: newY })
    },

    openChat() {
      wx.vibrateShort({ type: 'medium' })

      if (!isAIAvailable()) {
        wx.showToast({ title: 'AI功能暂未开放', icon: 'none' })
        return
      }

      const pages = getCurrentPages()
      const page = pages[pages.length - 1]
      if (page && typeof page.getTabBar === 'function' && page.getTabBar()) {
        page.getTabBar().setData({ hidden: true })
      }

      this.setData({ panelMounted: true })
      setTimeout(() => {
        this.setData({ visible: true })
        setTimeout(() => this.setData({ inputFocus: true }), 400)
      }, 30)
    },

    closeChat() {
      this.setData({ visible: false, inputFocus: false, keyboardHeight: 0 })

      // 关闭时恢复 TabBar
      const pages = getCurrentPages()
      const page = pages[pages.length - 1]
      if (page && typeof page.getTabBar === 'function' && page.getTabBar()) {
        page.getTabBar().setData({ hidden: false })
      }

      setTimeout(() => this.setData({ panelMounted: false }), 350)
    },

    clearChat() {
      if (this.data.sending) return
      wx.vibrateShort({ type: 'light' })
      this.setData({
        messages: [],
        inputValue: '',
        hasHistory: false,
        errorMsgId: '',
        scrollTarget: ''
      })
    },

    onInput(e) {
      this.setData({ inputValue: e.detail.value })
    },

    onQuickQuestion(e) {
      const q = e.currentTarget.dataset.q
      if (!q) return
      this.setData({ inputValue: q })
      this._doSend(q)
    },

    sendMessage() {
      const text = (this.data.inputValue || '').trim()
      if (!text || this.data.sending) return
      this._doSend(text)
    },

    retryLastMessage() {
      if (this.data.sending) return
      const msgs = this.data.messages
      if (!msgs.length) return

      const lastBot = msgs[msgs.length - 1]
      if (!lastBot || lastBot.role !== 'assistant') return

      let lastUserText = ''
      for (let i = msgs.length - 2; i >= 0; i--) {
        if (msgs[i].role === 'user') {
          lastUserText = msgs[i].content
          break
        }
      }
      if (!lastUserText) return

      const cleaned = msgs.slice(0, -2)
      this.setData({ messages: cleaned, errorMsgId: '' })
      setTimeout(() => this._doSend(lastUserText), 100)
    },

    async _doSend(text) {
      // 检查会员功能是否启用
      let membershipOn = false
      try { membershipOn = await isMembershipEnabled() } catch (e) {}

      if (membershipOn) {
        // 会员模式：免费3次/会员无限
        let memberState = null
        try { memberState = await getMembershipState() } catch (e) {}
        const remaining = getAiChatRemaining(memberState)
        if (remaining === 0) {
          wx.showModal({
            title: '今日次数已用完',
            content: '免费用户每日可提问 ' + FREE_LIMITS.AI_CHAT + ' 次，升级星际通行证可无限提问',
            confirmText: '去升级',
            cancelText: '明天再来',
            success: (res) => {
              if (res.confirm) {
                wx.navigateTo({ url: '/pages/profile/membership/membership' })
              }
            }
          })
          return
        }
      } else {
        // 非会员模式：使用原来的 10 次/日限制
        const remaining = getRemainingQuota()
        if (remaining <= 0) {
          wx.showToast({ title: '今日提问次数已用完，明天再来吧', icon: 'none', duration: 2500 })
          return
        }
      }

      const userMsg = { id: nextMsgId(), role: 'user', content: text }
      const botMsg = { id: nextMsgId(), role: 'assistant', content: '', typing: true, error: false }

      const messages = [...this.data.messages, userMsg, botMsg]
      this.setData({
        messages,
        inputValue: '',
        sending: true,
        hasHistory: true,
        errorMsgId: '',
        scrollTarget: 'msg-bottom'
      })

      const recentMessages = messages
        .filter(m => !m.typing && m.content && !m.error)
        .map(m => ({ role: m.role, content: m.content }))
        .slice(-(MAX_HISTORY_ROUNDS * 2))

      const botIdx = this.data.messages.length - 1
      const launchContext = this._getLaunchContext()

      try {
        await streamChat(recentMessages, (partial) => {
          this.setData({
            [`messages[${botIdx}].content`]: partial,
            [`messages[${botIdx}].typing`]: false,
            scrollTarget: 'msg-bottom'
          })
        }, launchContext)
        if (membershipOn) {
          recordAiChatUse()
        } else {
          incrementDailyQuota()
        }
      } catch (err) {
        const errorText = err.message || '抱歉，我暂时无法回答，请稍后再试。'
        this.setData({
          [`messages[${botIdx}].content`]: errorText,
          [`messages[${botIdx}].typing`]: false,
          [`messages[${botIdx}].error`]: true,
          errorMsgId: this.data.messages[botIdx].id
        })
      } finally {
        this.setData({ sending: false })
      }
    },

    _preloadLaunchData() {
      Promise.all([
        getUpcomingMissions(15, 0).catch(() => ({ list: [] })),
        getCompletedMissions(5, 0).catch(() => ({ list: [] }))
      ]).then(([upRes, compRes]) => {
        this._cachedUpcoming = upRes.list || []
        this._cachedCompleted = compRes.list || []
      })
    },

    _getLaunchContext() {
      try {
        const pages = getCurrentPages()
        const indexPage = pages.find(p => p.route === 'pages/index/index')
        const d = indexPage && indexPage.data

        let upcoming = []
        let completed = []
        let countdown = null

        if (d && d.launchData && d.launchData.name) {
          countdown = {
            name: d.launchData.name,
            rocketName: d.launchData.rocketName,
            launchTime: d.launchData.launchTime,
            launchAgency: d.launchData.launchAgency,
            launchSite: d.launchData.launchSite,
            status: d.launchData.status
          }
        }

        if (d && Array.isArray(d.upcomingMissions) && d.upcomingMissions.length > 0) {
          upcoming = d.upcomingMissions.slice(0, 15)
        } else if (Array.isArray(this._cachedUpcoming) && this._cachedUpcoming.length > 0) {
          upcoming = this._cachedUpcoming.slice(0, 15)
        }

        if (d && Array.isArray(d.completedMissions) && d.completedMissions.length > 0) {
          completed = d.completedMissions.slice(0, 5)
        } else if (Array.isArray(this._cachedCompleted) && this._cachedCompleted.length > 0) {
          completed = this._cachedCompleted.slice(0, 5)
        }

        if (!countdown && !upcoming.length && !completed.length) return null

        return {
          countdown,
          upcoming: upcoming.map(m => ({
            name: m.name || m.missionName,
            rocketName: m.rocketName,
            launchTime: m.launchTime,
            launchAgency: m.launchAgency,
            launchSite: m.launchSite || m.padLocation,
            status: m.status
          })),
          completed: completed.map(m => ({
            name: m.name || m.missionName,
            rocketName: m.rocketName,
            launchTime: m.launchTime,
            launchAgency: m.launchAgency,
            status: m.status
          }))
        }
      } catch (e) {}
      return null
    }
  }
})
