const { getUiShellLayout } = require('../../utils/layout.js')
const { ROUTES, navigateTo } = require('../../utils/routes.js')
const { getSystemInfo } = require('../../utils/system.js')

const VISIT_KEY = '_float_visit_'
const LUNAR_COUNT_KEY = '_float_lunar_count'
const LUNAR_CACHE_KEY = '_float_lunar_cache'
const LUNAR_CACHE_TTL = 30 * 60 * 1000

function todayStr() {
  const d = new Date()
  return d.getFullYear() + '-' + String(d.getMonth() + 1).padStart(2, '0') + '-' + String(d.getDate()).padStart(2, '0')
}

Component({
  options: { addGlobalClass: true },

  properties: {
    badgeCount: { type: Number, value: 0 },
    show: { type: Boolean, value: true }
  },

  observers: {
    'show': function (val) {
      this.setData({ visible: !!val })
    }
  },

  data: {
    visible: false,
    expanded: false,
    showDot: false,
    dotMap: {},
    btnX: 0,
    btnY: 0,
    windowWidth: 0,
    windowHeight: 0,
    btnSize: 48,
    safeLeft: 20,
    safeTop: 0,
    safeBottom: 0,
    particles: [],
    menuItems: [
      { key: 'nasa', label: 'NASA数据', icon: '', image: '/images/icons/nasa-logo.png' },
      { key: 'lunar', label: '月愿计划', icon: '', image: '/images/icons/moon-crescent.svg' },
      { key: 'astro', label: '天文日历', icon: '', image: '/images/icons/ic-telescope.svg' },
      { key: 'exoplanet', label: '系外行星', icon: '', image: '/images/icons/ic-exoplanet.svg' }
    ]
  },

  lifetimes: {
    attached() {
      const sys = getSystemInfo()
      const ratio = sys.windowWidth / 750
      const btnSize = Math.round(96 * ratio)

      const layout = getUiShellLayout(sys)
      const safeTop = layout.navPlaceholderHeight
      const safeBottom = layout.tabBarReservedHeight

      this.setData({
        visible: this.properties.show,
        windowWidth: sys.windowWidth,
        windowHeight: sys.windowHeight,
        btnSize,
        safeTop,
        safeBottom,
        btnX: sys.windowWidth - btnSize - 12,
        btnY: Math.round(sys.windowHeight * 0.65)
      })

      this._checkAllDots()
    }
  },

  methods: {
    onTouchStart(e) {
      this._touchTs = Date.now()
      const t = e.touches[0]
      this._startX = t.clientX
      this._startY = t.clientY
      this._startBtnX = this.data.btnX
      this._startBtnY = this.data.btnY
      this._isDragging = false
    },

    onTouchMove(e) {
      const t = e.touches[0]
      const dx = t.clientX - this._startX
      const dy = t.clientY - this._startY
      if (Math.abs(dx) > 5 || Math.abs(dy) > 5) {
        this._isDragging = true
      }
      const { btnSize, windowWidth, windowHeight, safeLeft, safeTop, safeBottom } = this.data
      const minY = safeTop
      const maxY = windowHeight - btnSize - safeBottom
      const newX = Math.max(safeLeft, Math.min(windowWidth - btnSize, this._startBtnX + dx))
      const newY = Math.max(minY, Math.min(maxY, this._startBtnY + dy))
      this.setData({ btnX: newX, btnY: newY })

      if (this._isDragging) {
        this._spawnParticle(newX + btnSize / 2, newY + btnSize / 2)
      }
    },

    onTouchEnd() {
      if (this._isDragging) {
        this._snapToEdge()
        this._fadeOutParticles()
        return
      }
      wx.vibrateShort({ type: 'medium' })
      this.setData({ expanded: !this.data.expanded })
    },

    _spawnParticle(cx, cy) {
      if (!this._particleList) this._particleList = []
      if (!this._particleId) this._particleId = 0
      const now = Date.now()
      if (this._lastParticleTs && now - this._lastParticleTs < 8) return
      this._lastParticleTs = now

      const offsetX = (Math.random() - 0.5) * 16
      const offsetY = (Math.random() - 0.5) * 16
      const size = 0.5 + Math.random() * 1.0
      const p = { id: ++this._particleId, x: cx + offsetX, y: cy + offsetY, opacity: 1, scale: size }
      this._particleList.push(p)
      if (this._particleList.length > 80) this._particleList = this._particleList.slice(-80)
      this.setData({ particles: this._particleList })

      setTimeout(() => {
        this._particleList = this._particleList.map(item =>
          item.id === p.id ? { ...item, opacity: 0, scale: 0.1 } : item
        )
        this.setData({ particles: this._particleList })
      }, 50)

      setTimeout(() => {
        this._particleList = this._particleList.filter(item => item.id !== p.id)
        this.setData({ particles: this._particleList })
      }, 1800)
    },

    _fadeOutParticles() {
      if (!this._particleList || !this._particleList.length) return
      this._particleList = this._particleList.map(p => ({ ...p, opacity: 0, scale: 0.05 }))
      this.setData({ particles: this._particleList })
      setTimeout(() => {
        this._particleList = []
        this.setData({ particles: [] })
      }, 1600)
    },

    onMenuTap(e) {
      wx.vibrateShort({ type: 'medium' })
      const key = e.currentTarget.dataset.key
      this.setData({ expanded: false })
      this._markVisited(key)
      if (key === 'nasa') {
        navigateTo(ROUTES.NASA_DATA)
      } else if (key === 'lunar') {
        navigateTo(ROUTES.LUNAR_WISHES)
      } else if (key === 'astro') {
        navigateTo(ROUTES.ASTRO_CALENDAR)
      } else if (key === 'exoplanet') {
        navigateTo(ROUTES.EXOPLANET)
      }
    },

    onMaskTap() {
      this.setData({ expanded: false })
    },

    _snapToEdge() {
      const { btnX, btnY, windowWidth, windowHeight, btnSize, safeLeft, safeTop, safeBottom } = this.data
      const edgeMargin = 12
      const newX = (btnX + btnSize / 2) < (windowWidth / 2) ? edgeMargin : windowWidth - btnSize - edgeMargin
      const minY = safeTop
      const maxY = windowHeight - btnSize - safeBottom
      const newY = Math.max(minY, Math.min(maxY, btnY))
      this.setData({ btnX: newX, btnY: newY })
    },

    // ---- 内容驱动的红点系统 ----

    _checkAllDots() {
      const today = todayStr()
      const map = {}

      // 天文日历：APOD 每天更新，当天未查看则显示红点
      try { map.astro = wx.getStorageSync(VISIT_KEY + 'astro') !== today }
      catch (e) { map.astro = true }

      // NASA数据：每天有新内容，当天未查看则显示红点
      try { map.nasa = wx.getStorageSync(VISIT_KEY + 'nasa') !== today }
      catch (e) { map.nasa = true }

      // 系外行星：静态策展数据，无红点
      map.exoplanet = false

      // 月愿计划：需异步查云端，先不显示
      map.lunar = false

      this.setData({
        dotMap: map,
        showDot: Object.keys(map).some(k => map[k])
      })

      this._checkLunarDot()
    },

    _checkLunarDot() {
      try {
        const cache = wx.getStorageSync(LUNAR_CACHE_KEY)
        if (cache && cache.ts && Date.now() - cache.ts < LUNAR_CACHE_TTL) {
          if (cache.dot) this._setDot('lunar', true)
          return
        }
      } catch (e) {}

      const { cloudEnv } = require('../../utils/config.js')
      wx.cloud.callFunction({
        name: 'lunarWishes',
        config: { env: cloudEnv },
        data: { action: 'stats' }
      }).then(res => {
        const result = res.result || {}
        if (result.code === 0 && result.data) {
          const current = result.data.totalWishes || 0
          let lastSeen = 0
          try { lastSeen = wx.getStorageSync(LUNAR_COUNT_KEY) || 0 } catch (e) {}
          const hasDot = current > lastSeen
          this._setDot('lunar', hasDot)
          try {
            wx.setStorageSync(LUNAR_CACHE_KEY, { ts: Date.now(), dot: hasDot, total: current })
          } catch (e) {}
        }
      }).catch(() => {})
    },

    _setDot(key, hasDot) {
      const dotMap = Object.assign({}, this.data.dotMap)
      dotMap[key] = hasDot
      this.setData({
        dotMap: dotMap,
        showDot: Object.keys(dotMap).some(k => dotMap[k])
      })
    },

    _markVisited(key) {
      if (key === 'astro' || key === 'nasa') {
        try { wx.setStorageSync(VISIT_KEY + key, todayStr()) } catch (e) {}
      } else if (key === 'lunar') {
        try {
          const cache = wx.getStorageSync(LUNAR_CACHE_KEY)
          if (cache && cache.total) {
            wx.setStorageSync(LUNAR_COUNT_KEY, cache.total)
            wx.setStorageSync(LUNAR_CACHE_KEY, Object.assign({}, cache, { dot: false }))
          }
        } catch (e) {}
      }
      this._setDot(key, false)
    }
  }
})
